            aOrbiterB = (aWandererC + RotL64(aCross, 39U)) + 0xD4C9B79782F2D1C9ULL;
            aOrbiterG = ((aWandererA + RotL64(aIngress, 52U)) + RotL64(aCarry, 21U)) + 0x275BC84A91143555ULL;
