            aOrbiterG = ((aOrbiterG ^ aOrbiterB) ^ 0x90414CE043E4E1CCULL) ^ aPhaseBOrbiterUpdateSaltE[((aIndex + 4U)) & 31];
            aOrbiterG = RotL64((aOrbiterG * 0x210ACB27D31EC39FULL), 19U);
