            //
            aOrbiterJ = (aOrbiterJ + aOrbiterH) + 0xB5483B6E08D255ACULL;
            aOrbiterA = (aOrbiterA ^ aOrbiterJ) ^ 0x352B346D54B6DE9AULL;
