            aWandererD = aWandererD + ((RotL64(aPrevious, 23U) + RotL64(aOrbiterK, 3U)) + aOrbiterC);
            aWandererC = aWandererC ^ ((RotL64(aIngress, 21U) + RotL64(aOrbiterH, 11U)) + aOrbiterC);
